    fun v(tag: String = DEFAULT_TAG, message: String) = log(Log.VERBOSE, tag, message)
    fun d(tag: String = DEFAULT_TAG, message: String) = log(Log.DEBUG, tag, message)
    fun i(tag: String = DEFAULT_TAG, message: String) = log(Log.INFO, tag, message)
    fun w(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) = log(Log.WARN, tag, message, throwable)
    fun e(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) = log(Log.ERROR, tag, message, throwable)
    fun wtf(tag: String = DEFAULT_TAG, message: String, throwable: Throwable? = null) = log(Log.ASSERT, tag, message, throwable)

