    private fun log(priority: Int, tag: String, message: String, throwable: Throwable? = null) {
        val fullMessage = if (throwable != null) {
            if (message.isBlank()) Log.getStackTraceString(throwable)
            else "$message\n${Log.getStackTraceString(throwable)}"
        } else {
            message
        }

        if (fullMessage.length <= MAX_LOG_CHUNK_SIZE) {
            when (priority) {
                Log.VERBOSE -> Timber.tag(tag).v(fullMessage)
                Log.DEBUG -> Timber.tag(tag).d(fullMessage)
                Log.INFO -> Timber.tag(tag).i(fullMessage)
                Log.WARN -> Timber.tag(tag).w(fullMessage)
                Log.ERROR -> Timber.tag(tag).e(fullMessage)
                Log.ASSERT -> Timber.tag(tag).wtf(fullMessage)
                else -> Timber.tag(tag).d(fullMessage)
            }
            return
        }

        var index = 0
        while (index < fullMessage.length) {
            val end = (index + MAX_LOG_CHUNK_SIZE).coerceAtMost(fullMessage.length)
            val chunk = fullMessage.substring(index, end)
            when (priority) {
                Log.VERBOSE -> Timber.tag(tag).v(chunk)
                Log.DEBUG -> Timber.tag(tag).d(chunk)
                Log.INFO -> Timber.tag(tag).i(chunk)
                Log.WARN -> Timber.tag(tag).w(chunk)
                Log.ERROR -> Timber.tag(tag).e(chunk)
                Log.ASSERT -> Timber.tag(tag).wtf(chunk)
                else -> Timber.tag(tag).d(chunk)
            }
            index = end
        }
    }

    private class VerboseTree : Timber.DebugTree() {
        override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
            val actualTag = tag ?: DEFAULT_TAG
            if (message.length < MAX_LOG_CHUNK_SIZE) {
                Log.println(priority, actualTag, message)
            } else {
                var i = 0
                while (i < message.length) {
                    val newline = message.indexOf('\n', i).let { if (it == -1) message.length else it }
                    do {
                        val end = minOf(newline, i + MAX_LOG_CHUNK_SIZE)
                        Log.println(priority, actualTag, message.substring(i, end))
                        i = end
                    } while (i < newline)
                    i++
                }
            }
            if (t != null) {
                Log.println(priority, actualTag, Log.getStackTraceString(t))
            }
        }
