class FullLoggingInterceptor(
    private val logRequestBody: Boolean = true,
    private val logResponseBody: Boolean = true
) : Interceptor {

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val startNs = System.nanoTime()

        val requestHeadersMap = request.headers.toMap()
        val requestBodyString = if (logRequestBody) request.body?.safeReadAsString() else null

        ProductionLogger.logApiRequest(
            method = request.method,
            url = request.url.toString(),
            headers = requestHeadersMap,
            requestBody = requestBodyString
        )

        return try {
            val response = chain.proceed(request)
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)

            val responseHeadersMap = response.headers.toMap()
            val responseBodyString = if (logResponseBody) response.peekBody(Long.MAX_VALUE).string() else null

            ProductionLogger.logApiRequest(
                method = request.method,
                url = request.url.toString(),
                headers = requestHeadersMap,
                requestBody = requestBodyString,
                responseCode = response.code,
                responseHeaders = responseHeadersMap,
                responseBody = responseBodyString,
                durationMs = tookMs
            )

            response
        } catch (e: Exception) {
            val tookMs = TimeUnit.NANOSECONDS.toMillis(System.nanoTime() - startNs)
            ProductionLogger.logApiRequest(
                method = request.method,
                url = request.url.toString(),
                headers = requestHeadersMap,
                requestBody = requestBodyString,
                durationMs = tookMs,
                throwable = e
            )
            throw e
        }
    }
}

object LoggingOkHttpFactory {
    fun create(clientBuilder: OkHttpClient.Builder = OkHttpClient.Builder()): OkHttpClient {
        return clientBuilder
            .addInterceptor(FullLoggingInterceptor())
            .build()
    }
}

