object GlobalExceptionLogger : Thread.UncaughtExceptionHandler {
    private var defaultHandler: Thread.UncaughtExceptionHandler? = null

    fun install() {
        defaultHandler = Thread.getDefaultUncaughtExceptionHandler()
        Thread.setDefaultUncaughtExceptionHandler(this)
    }

    override fun uncaughtException(thread: Thread, throwable: Throwable) {
        ProductionLogger.logException(
            tag = "UncaughtException",
            throwable = throwable,
            message = "Uncaught exception on thread=${thread.name}"
        )
        defaultHandler?.uncaughtException(thread, throwable)
    }
}

private fun Headers.toMap(): Map<String, String> {
    val map = linkedMapOf<String, String>()
    for (i in 0 until size) {
        map[name(i)] = value(i)
    }
    return map
}

private fun RequestBody.safeReadAsString(): String? {
    return try {
        val buffer = Buffer()
        writeTo(buffer)
        val charset = contentType().charsetOrUtf8()
        buffer.readString(charset)
    } catch (e: IOException) {
        "!! failed to read request body: ${e.message}"
    } catch (e: Exception) {
        "!! failed to read request body: ${e.message}"
    }
}

private fun MediaType?.charsetOrUtf8(): Charset {
    return this?.charset(Charsets.UTF_8) ?: Charsets.UTF_8
}

fun Request.withJsonBody(json: String): Request {
    val mediaType = "application/json; charset=utf-8".toMediaTypeOrNull()
    val body = json.toRequestBody(mediaType)
    return newBuilder().method(method, body).build()
}